// 80km/h 제한 도로 단속 카메라
// 속도 범위: 60~100 km/h (80 ± 20)
const SPEED_LIMIT = 80;
const SPEED_MIN   = 60;
const SPEED_MAX   = 100;
const LOCATION    = '국도 17호선 단속구간 15.2km 지점';

const VEHICLE_TYPES = [
  '승용차', 'SUV', '트럭', '버스', '오토바이', '밴', '택시'
];

const results = [];

for (let vehicleNo = 1; vehicleNo <= 2; vehicleNo++) {
  const speed       = Math.floor(Math.random() * (SPEED_MAX - SPEED_MIN + 1)) + SPEED_MIN;
  const vehicleType = VEHICLE_TYPES[Math.floor(Math.random() * VEHICLE_TYPES.length)];
  const status      = speed > SPEED_LIMIT ? '과속' : '정상';

  console.log(`[차량 ${vehicleNo}] ${vehicleType} | 속도: ${speed} km/h | ${status}`);

  results.push({
    json: {
      vehicle_no:   vehicleNo,
      vehicle_type: vehicleType,
      speed_kmh:    speed,
      speed_limit:  SPEED_LIMIT,
      status:       status,
      location:     LOCATION
    }
  });
}

return results;
